/**
 * WebSocket message models for Opinion CLOB SDK
 *
 * This module provides type definitions for WebSocket messages to improve type safety
 * and ease of use.
 */

/**
 * Base WebSocket message interface
 */
export interface BaseWebSocketMessage {
  msgType: string;
}

/**
 * Market depth diff message received from WebSocket.
 *
 * This message is received when subscribing to 'market.depth.diff' channel.
 */
export interface MarketDepthDiffMessage extends BaseWebSocketMessage {
  /** Market ID */
  marketId: number;
  /** Root market ID if belongs to a categorical market */
  rootMarketId?: number;
  /** Position ID of updated token */
  tokenId: string;
  /** 1 - yes, 2 - no */
  outcomeSide: number;
  /** bids | asks */
  side: string;
  /** Price */
  price: string;
  /** Size in shares */
  size: string;
}

/**
 * Market last price message received from WebSocket.
 *
 * This message is received when subscribing to 'market.last.price' channel.
 */
export interface MarketLastPriceMessage extends BaseWebSocketMessage {
  /** Market ID */
  marketId: number;
  /** Root market ID if belongs to a categorical market */
  rootMarketId?: number;
  /** Position ID of traded token */
  tokenId: string;
  /** Price */
  price: string;
  /** 1 - yes, 2 - no */
  outcomeSide: number;
}

/**
 * Market last trade message received from WebSocket.
 *
 * This message is received when subscribing to 'market.last.trade' channel.
 */
export interface MarketLastTradeMessage extends BaseWebSocketMessage {
  /** Market ID */
  marketId: number;
  /** Root market ID if belongs to a categorical market */
  rootMarketId?: number;
  /** Position ID of traded token */
  tokenId: string;
  /** Buy | Sell | Split | Merge */
  side: string;
  /** 1 - yes, 2 - no */
  outcomeSide: number;
  /** Price */
  price: string;
  /** Shares */
  shares: string;
  /** Amount */
  amount: string;
}

/**
 * Trade order update message received from WebSocket.
 *
 * This message is received when subscribing to 'trade.order.update' channel.
 */
export interface TradeOrderUpdateMessage extends BaseWebSocketMessage {
  /** orderNew | orderFill | orderCancel | orderConfirm */
  orderUpdateType: string;
  /** Market ID */
  marketId: number;
  /** Root market ID if belongs to a categorical market */
  rootMarketId?: number;
  /** Order ID */
  orderId: string;
  /** 1 - buy, 2 - sell */
  side: number;
  /** 1 - yes, 2 - no */
  outcomeSide: number;
  /** Price */
  price: string;
  /** Shares */
  shares: string;
  /** Amount */
  amount: string;
  /** 1 - pending, 2 - finished, 3 - canceled, 4 - expired, 5 - failed */
  status: number;
  /** 1 - market price, 2 - limit price */
  tradingMethod: number;
  /** Contract address of quote token */
  quoteToken: string;
  /** Create unix timestamp */
  createdAt: number;
  /** Expire unix timestamp */
  expiresAt: number;
  /** Chain ID */
  chainId: string;
  /** Filled in shares, update after orderConfirm */
  filledShares: string;
  /** Filled in amount, update after orderConfirm */
  filledAmount: string;
}

/**
 * Trade record new message received from WebSocket.
 *
 * This message is received when subscribing to 'trade.record.new' channel.
 */
export interface TradeRecordNewMessage extends BaseWebSocketMessage {
  /** Order ID */
  orderId: string;
  /** Trade ID */
  tradeNo: string;
  /** Market ID */
  marketId: number;
  /** Root market ID if belongs to a categorical market */
  rootMarketId?: number;
  /** Transaction hash on-chain */
  txHash: string;
  /** Buy | Sell | Split | Merge */
  side: string;
  /** 1 - yes, 2 - no */
  outcomeSide: number;
  /** Price */
  price: string;
  /** Shares */
  shares: string;
  /** Amount */
  amount: string;
  /** Profit, applicable for sell/merge */
  profit: string;
  /** 2 - finished, 3 - canceled, 5 - failed, 6 - onchain failed */
  status: number;
  /** Contract address of quote token */
  quoteToken: string;
  /** USD price of quote token at the moment */
  quoteTokenUsdPrice: string;
  /** Amount in USD value */
  usdAmount: string;
  /** Fee applied to this trade */
  fee: string;
  /** Chain ID */
  chainId: string;
  /** Create unix timestamp */
  createdAt: number;
}

/**
 * WebSocket channel names
 */
export enum WebSocketChannel {
  MARKET_DEPTH_DIFF = 'market.depth.diff',
  MARKET_LAST_PRICE = 'market.last.price',
  MARKET_LAST_TRADE = 'market.last.trade',
  TRADE_ORDER_UPDATE = 'trade.order.update',
  TRADE_RECORD_NEW = 'trade.record.new',
}

/**
 * WebSocket action types
 */
export enum WebSocketAction {
  SUBSCRIBE = 'SUBSCRIBE',
  UNSUBSCRIBE = 'UNSUBSCRIBE',
  HEARTBEAT = 'HEARTBEAT',
}

/**
 * Subscribe message for binary market
 */
export interface SubscribeMessageBinary {
  action: WebSocketAction;
  channel: WebSocketChannel | string;
  marketId: number;
}

/**
 * Subscribe message for categorical market
 */
export interface SubscribeMessageCategorical {
  action: WebSocketAction;
  channel: WebSocketChannel | string;
  rootMarketId: number;
}

/**
 * Heartbeat message
 */
export interface HeartbeatMessage {
  action: WebSocketAction.HEARTBEAT;
}

/**
 * Union type for all subscription messages
 */
export type SubscribeMessage = SubscribeMessageBinary | SubscribeMessageCategorical;

/**
 * Union type for all WebSocket messages
 */
export type WebSocketMessage =
  | MarketDepthDiffMessage
  | MarketLastPriceMessage
  | MarketLastTradeMessage
  | TradeOrderUpdateMessage
  | TradeRecordNewMessage;

/**
 * Parser functions for WebSocket messages
 */
export function parseMarketDepthDiffMessage(data: Record<string, unknown>): MarketDepthDiffMessage {
  return {
    marketId: Number(data.marketId ?? 0),
    rootMarketId: data.rootMarketId != null ? Number(data.rootMarketId) : undefined,
    tokenId: String(data.tokenId ?? ''),
    outcomeSide: Number(data.outcomeSide ?? 0),
    side: String(data.side ?? ''),
    price: String(data.price ?? '0'),
    size: String(data.size ?? '0'),
    msgType: String(data.msgType ?? ''),
  };
}

export function parseMarketLastPriceMessage(data: Record<string, unknown>): MarketLastPriceMessage {
  return {
    marketId: Number(data.marketId ?? 0),
    rootMarketId: data.rootMarketId != null ? Number(data.rootMarketId) : undefined,
    tokenId: String(data.tokenId ?? ''),
    price: String(data.price ?? '0'),
    outcomeSide: Number(data.outcomeSide ?? 0),
    msgType: String(data.msgType ?? ''),
  };
}

export function parseMarketLastTradeMessage(data: Record<string, unknown>): MarketLastTradeMessage {
  return {
    marketId: Number(data.marketId ?? 0),
    rootMarketId: data.rootMarketId != null ? Number(data.rootMarketId) : undefined,
    tokenId: String(data.tokenId ?? ''),
    side: String(data.side ?? ''),
    outcomeSide: Number(data.outcomeSide ?? 0),
    price: String(data.price ?? '0'),
    shares: String(data.shares ?? '0'),
    amount: String(data.amount ?? '0'),
    msgType: String(data.msgType ?? ''),
  };
}

export function parseTradeOrderUpdateMessage(
  data: Record<string, unknown>
): TradeOrderUpdateMessage {
  return {
    orderUpdateType: String(data.orderUpdateType ?? ''),
    marketId: Number(data.marketId ?? 0),
    rootMarketId:
      data.rootMarketId != null && Number(data.rootMarketId) !== 0
        ? Number(data.rootMarketId)
        : undefined,
    orderId: String(data.orderId ?? ''),
    side: Number(data.side ?? 0),
    outcomeSide: Number(data.outcomeSide ?? 0),
    price: String(data.price ?? '0'),
    shares: String(data.shares ?? '0'),
    amount: String(data.amount ?? '0'),
    status: Number(data.status ?? 0),
    tradingMethod: Number(data.tradingMethod ?? 0),
    quoteToken: String(data.quoteToken ?? ''),
    createdAt: Number(data.createdAt ?? 0),
    expiresAt: Number(data.expiresAt ?? 0),
    chainId: String(data.chainId ?? ''),
    filledShares: String(data.filledShares ?? '0'),
    filledAmount: String(data.filledAmount ?? '0'),
    msgType: String(data.msgType ?? ''),
  };
}

export function parseTradeRecordNewMessage(data: Record<string, unknown>): TradeRecordNewMessage {
  return {
    orderId: String(data.orderId ?? ''),
    tradeNo: String(data.tradeNo ?? ''),
    marketId: Number(data.marketId ?? 0),
    rootMarketId:
      data.rootMarketId != null && Number(data.rootMarketId) !== 0
        ? Number(data.rootMarketId)
        : undefined,
    txHash: String(data.txHash ?? ''),
    side: String(data.side ?? ''),
    outcomeSide: Number(data.outcomeSide ?? 0),
    price: String(data.price ?? '0'),
    shares: String(data.shares ?? '0'),
    amount: String(data.amount ?? '0'),
    profit: String(data.profit ?? '0'),
    status: Number(data.status ?? 0),
    quoteToken: String(data.quoteToken ?? ''),
    quoteTokenUsdPrice: String(data.quoteTokenUsdPrice ?? '0'),
    usdAmount: String(data.usdAmount ?? '0'),
    fee: String(data.fee ?? ''),
    chainId: String(data.chainId ?? ''),
    createdAt: Number(data.createdAt ?? 0),
    msgType: String(data.msgType ?? ''),
  };
}
